sql:
SELECT * 
FROM size_guides
WHERE size_label = 'XS';

SELECT DISTINCT c.full_name
FROM customers c
JOIN orders o ON c.customer_id = o.customer_id;

external_knowledge:
"size ID 0" can refer to a generic or unspecified size category in the size guide;
"found it useful" means the customer marked `is_helpful` as true (1);
"made purchases" indicates that these customers have placed orders in the system.

sql:
SELECT COUNT(*) 
FROM feedback 
WHERE is_helpful = 0;

SELECT c.full_name, c.email
FROM customers c
WHERE EXISTS (SELECT 1 FROM feedback f WHERE f.customer_id = c.customer_id);

SELECT size_label, recommended_sizes
FROM size_guides
WHERE size_id = 1;

SELECT COUNT(DISTINCT o.customer_id) 
FROM returns r
JOIN orders o ON r.order_id = o.order_id;
